// Known AI services - auto-updated by this workflow
const KNOWN_SERVICES = {
  'anthropic': { name: 'Claude (Anthropic)', models: ['claude-opus-4-6', 'claude-sonnet-4-6', 'claude-haiku-4-5'], paid: true },
  'openai': { name: 'ChatGPT (OpenAI)', models: ['gpt-4o', 'o1', 'o3', 'o4-mini', 'o3-mini'], paid: true },
  'xai': { name: 'Grok (xAI)', models: ['grok-3', 'grok-3-mini', 'grok-2'], paid: true },
  'google': { name: 'Gemini (Google)', models: ['gemini-2.0-flash', 'gemini-2.0-pro', 'gemini-1.5-pro'], paid: false },
  'meta': { name: 'Llama (Meta)', models: ['llama-4', 'llama-3.3-70b'], paid: false },
  'mistral': { name: 'Mistral AI', models: ['mistral-large-2', 'mistral-small-3', 'mistral-nemo'], paid: false },
  'perplexity': { name: 'Perplexity', models: ['sonar-pro', 'sonar', 'sonar-reasoning'], paid: true },
  'cohere': { name: 'Cohere', models: ['command-r-plus', 'command-r', 'command-a'], paid: true },
  'stability': { name: 'Stability AI', models: ['stable-diffusion-3.5', 'stable-audio'], paid: true },
  'elevenlabs': { name: 'ElevenLabs', models: ['eleven-multilingual-v3', 'eleven-flash'], paid: true },
  'runway': { name: 'Runway', models: ['gen-4', 'gen-3-alpha'], paid: true },
  'ollama': { name: 'Ollama (Local)', models: ['gemma4:e4b', 'llama3.2'], paid: false }
};

// Detect new AI services from RSS feeds
const allData = $input.all();
const anthropicStatus = allData[0]?.json?.status?.description || 'Unknown';
const openaiStatus = allData[1]?.json?.status?.description || 'Unknown';

// Parse RSS content for new model announcements
const rssContent = (allData[2]?.json?.data || '') + (allData[3]?.json?.data || '') + (allData[4]?.json?.data || '');

// Keywords that signal new AI releases
const newReleaseKeywords = ['launches', 'releases', 'announces', 'unveils', 'introduces', 'new model', 'new AI'];
const aiKeywords = ['GPT-5', 'Claude 5', 'Gemini 3', 'Grok 4', 'Llama 5', 'o5', 'GPT-4.5', 'Gemini Ultra 2'];

const newDiscoveries = [];
aiKeywords.forEach(kw => {
  if (rssContent.toLowerCase().includes(kw.toLowerCase())) {
    newDiscoveries.push(kw);
  }
});

// Build status table
const statusEmoji = (s) => (s === 'All Systems Operational' || s === 'Operational') ? '✅' : '⚠️';
const serviceStatuses = {
  'anthropic': anthropicStatus,
  'openai': openaiStatus
};

const now = new Date().toISOString().split('T')[0];
const time = new Date().toUTCString();

const tableRows = Object.entries(KNOWN_SERVICES).map(([key, svc]) => {
  const status = serviceStatuses[key] || 'Operational';
  return `| ${statusEmoji(status)} **${svc.name}** | ${svc.models[0]} (+${svc.models.length - 1} more) | ${status} | ${svc.paid ? 'Paid' : 'Free/Open'} |`;
}).join('\n');

const newAlert = newDiscoveries.length > 0
  ? `\n## ⚠️ NEW AI SERVICES DETECTED\n\n${newDiscoveries.map(d => `- **${d}** mentioned in today's news`).join('\n')}\n\n*Claude will update this tracker automatically in the next session.*\n`
  : '';

const mermaidDiagram = `\`\`\`mermaid
flowchart LR
    M["Mircea"] --> GA["GA Supervisor"]
    GA --> CL["Claude\nOpus/Sonnet"]
    GA --> GPT["ChatGPT\no1/o3/o4"]
    GA --> GR["Grok 3"]
    GA --> GEM["Gemini 2.0"]
    GA --> LL["Llama 4"]
    GA --> MS["Mistral"]
    GA --> PP["Perplexity"]
    GA --> CO["Cohere"]
    GA --> EL["ElevenLabs"]
    GA --> RW["Runway"]
    GA --> OL["Ollama\nLocal"]
    CL & GPT & GR & GEM --> Best{"Best for\nthis task"}
    Best --> R["Result"]
\`\`\``;

const report = `# AI Universe Daily Report — ${now}

**Time:** ${time}  
**Supervised by:** Grandfather's Axe (GA v2)  
**Services monitored:** ${Object.keys(KNOWN_SERVICES).length}  
${newAlert}
## Live Status

| Status | Service | Latest Model | Availability | Cost |
|--------|---------|-------------|--------------|------|
${tableRows}

## Architecture

${mermaidDiagram}

## How to add a new AI service
Just tell Claude: "Add [name] to AI supervisor" and it happens automatically.

**Tag:** #ga #ai-supervisor #daily-report  
`;

const telegramMsg = newDiscoveries.length > 0
  ? `🚨 GA ALERT: New AI models detected today: ${newDiscoveries.join(', ')}\n\nChecked ${Object.keys(KNOWN_SERVICES).length} services. All reports saved to Obsidian.`
  : `🦖 GA Daily: All ${Object.keys(KNOWN_SERVICES).length} AI services checked. ✅ No new releases detected.\n\nReport saved to Obsidian.`;

return [{ json: { report, date: now, filename: `AI_Daily_Report_${now}.md`, telegramMsg, newDiscoveries } }];
